defmodule MyAppWeb.UserController do
  use MyAppWeb, :controller

  alias MyApp.Accounts

  action_fallback MyAppWeb.FallbackController

  plug :authorize_user_access when action in [:update]

  def update(conn, %{"id" => id} = params) do
    user = Accounts.get_user!(id)
    current_user = conn.assigns.current_user

    user_params = Map.drop(params, ["id"])

    result =
      if current_user.role == "admin" do
        Accounts.update_user(user, user_params, :admin)
      else
        sanitized_params = Map.drop(user_params, ["role", "is_active"])
        Accounts.update_user(user, sanitized_params)
      end

    case result do
      {:ok, updated_user} ->
        conn
        |> put_status(:ok)
        |> render(:show, user: updated_user)

      {:error, changeset} ->
        conn
        |> put_status(:unprocessable_entity)
        |> render(:errors, changeset: changeset)
    end
  end

  defp authorize_user_access(conn, _opts) do
    current_user = conn.assigns[:current_user]
    requested_user_id = conn.params["id"]

    cond do
      is_nil(current_user) ->
        conn
        |> put_status(:unauthorized)
        |> Phoenix.Controller.json(%{error: "Authentication required"})
        |> halt()

      current_user.role == "admin" ->
        conn

      to_string(current_user.id) == to_string(requested_user_id) ->
        conn

      true ->
        conn
        |> put_status(:forbidden)
        |> Phoenix.Controller.json(%{error: "You are not authorized to update this user"})
        |> halt()
    end
  end
end

defmodule MyAppWeb.FallbackController do
  use MyAppWeb, :controller

  def call(conn, {:error, :not_found}) do
    conn
    |> put_status(:not_found)
    |> json(%{error: "Resource not found"})
  end

  def call(conn, {:error, :unauthorized}) do
    conn
    |> put_status(:unauthorized)
    |> json(%{error: "Unauthorized"})
  end

  def call(conn, {:error, %Ecto.Changeset{} = changeset}) do
    conn
    |> put_status(:unprocessable_entity)
    |> json(%{errors: format_changeset_errors(changeset)})
  end

  defp format_changeset_errors(changeset) do
    Ecto.Changeset.traverse_errors(changeset, fn {msg, opts} ->
      Regex.replace(~r"%{(\w+)}", msg, fn _, key ->
        opts |> Keyword.get(String.to_existing_atom(key), key) |> to_string()
      end)
    end)
  end
end

defmodule MyAppWeb.UserJSON do
